<?php defined('ABSPATH') || exit; class FounderKit_Addons { public function get_available(): array { return ['fk-forms-pro'=>['name'=>'Forms Pro','description'=>'Advanced lead forms and funnel flows.','price'=>'premium','status'=>'coming_soon'],'fk-lms-pro'=>['name'=>'LMS Pro','description'=>'Cohorts, certificates, drip content, analytics.','price'=>'premium','status'=>'coming_soon'],'fk-woo-pro'=>['name'=>'Woo Pro','description'=>'Digital checkout enhancements and funnels.','price'=>'premium','status'=>'coming_soon'],'fk-starter-templates'=>['name'=>'Starter Templates','description'=>'Fast import templates for agencies and academies.','price'=>'free','status'=>'available']]; } public function get_active(): array { $s=new FounderKit_Settings(); $active=$s->get('active_addons')?:[]; $out=[]; $license=new FounderKit_License(); foreach($this->get_available() as $slug=>$addon){ $is_enabled=in_array($slug,$active,true); $is_licensed=($addon['price']==='free')?true:$license->is_valid(); $addon['active']=$is_enabled&&$is_licensed; $addon['license_status']=$this->get_addon_license_status($slug); $out[$slug]=$addon; } return $out; } public function is_active(string $slug): bool { $s=new FounderKit_Settings(); $enabled=in_array($slug,$s->get('active_addons')?:[],true); if(!$enabled){ return false; } $addon=$this->get_available()[$slug]??null; if(!$addon){ return false; } if($addon['price']==='free'){ return true; } $license=new FounderKit_License(); return $license->is_valid(); } public function get_addon_license_status(string $slug): string { $addon=$this->get_available()[$slug]??null; if(!$addon){ return 'unknown'; } if($addon['price']==='free'){ return 'free'; } $license=new FounderKit_License(); if(!$license->is_valid()){ return 'unlicensed'; } return 'licensed'; } public function is_addon_licensed(string $slug): bool { return $this->get_addon_license_status($slug)==='licensed'; } }

